import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-download.IKA_571t.js";const a=JSON.parse(`{"title":"设置 IntelliJ IDEA","description":"有关如何搭建 IntelliJ IDEA 以使用 Fabric 创作模组的逐步指南。","frontmatter":{"title":"设置 IntelliJ IDEA","description":"有关如何搭建 IntelliJ IDEA 以使用 Fabric 创作模组的逐步指南。","authors":["2xsaiko","Andrew6rant","asiekierka","Daomephsta","dicedpixels","falseresync","IMB11","liach","mkpoli","modmuss50","natanfudge","SolidBlock-cn","TelepathicGrunt"],"authors-nogithub":["siglong"],"prev":{"text":"设置你的 IDE","link":"../setting-up"},"next":{"text":"在 IntelliJ IDEA 中打开项目","link":"./opening-a-project"},"files":[]},"headers":[],"relativePath":"zh_cn/develop/getting-started/intellij-idea/setting-up.md","filePath":"translated/zh_cn/develop/getting-started/intellij-idea/setting-up.md","lastUpdated":1771183440000}`);var o={name:`zh_cn/develop/getting-started/intellij-idea/setting-up.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">设置 IntelliJ IDEA <a class="header-anchor" href="#h1" aria-label="Permalink to “设置 IntelliJ IDEA”">​</a></h1><div class="info custom-block"><p class="custom-block-title">先决条件</p><p>请确保先<a href="./../setting-up#install-jdk-21">安装 JDK</a>。</p></div><h2 id="installing-intellij-idea" tabindex="-1">安装 IntelliJ IDEA <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “安装 IntelliJ IDEA”">​</a></h2><p>如果没有安装 IntelliJ IDEA，可以从<a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">官方网站</a>下载——按照你的操作系统的安装步骤操作。</p><p><img src="/assets/develop/getting-started/idea-download.png" alt="IntelliJ IDEA 下载提示" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">安装“Minecraft Development”插件 <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “安装“Minecraft Development”插件”">​</a></h2><p>Minecraft Development 插件为使用 Fabric 开发模组提供支持，是要安装的最重要的插件。</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>这个插件虽然不是必需的，但能让利用 Fabric 制作模组容易得多——所以应该考虑安装。</p></div><p>如要安装，可以打开 IntelliJ IDEA，然后导航到 <strong>文件</strong> &gt; <strong>设置</strong> &gt; <strong>插件</strong> &gt; <strong>市场</strong> 标签页，然后在搜索栏中搜索 <code>Minecraft Development</code>，然后单击 <strong>安装</strong> 按钮。</p><p>或者，你可以在<a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">插件页面</a>下载，再依次进入<strong>文件</strong> &gt; <strong>设置</strong> &gt; <strong>插件</strong> &gt; <strong>从磁盘安装插件</strong>以安装。</p><h3 id="about-creating-a-project" tabindex="-1">关于创建项目 <a class="header-anchor" href="#about-creating-a-project" aria-label="Permalink to “关于创建项目”">​</a></h3><p>虽然可以使用此插件创建项目，但不建议这样做，因为模板经常会过期。 你可以考虑按照<a href="./../creating-a-project">创建项目</a>中的说明使用 Fabric 模板模组生成器。</p>`,12)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};